const text = $('Build Full Document').item.json.full_text;
const chunkSize = 1200;
const overlap = 200;

const chunks = [];
let start = 0;
let index = 0;

while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunk = text.slice(start, end);

  chunks.push({
    json: {
      document_id: $('Upsert Document Metadata').first().json.id,
      chunk_index: index,
      chunk_text: chunk,
      file_name: $('Build Full Document').item.json.file_name,
      document_date: $('Build Full Document').item.json.document_date
    }
  });

  start += (chunkSize - overlap);
  index++;
}

return chunks;

const embedding =
  $json.embedding?.values ||
  $json.embeddings?.[0]?.values ||
  $json.values ||
  null;

if (!embedding) {
  throw new Error('No se pudo extraer el vector de embedding');
}

return [
  {
    json: {
      document_id: $('Loop Chunks').item.json.document_id,
      chunk_index: $('Loop Chunks').item.json.chunk_index,
      chunk_text: $('Loop Chunks').item.json.chunk_text,
      embedding: `[${embedding.join(',')}]`
    }
  }
];

return [
  {
    json: {
      ok: true,
      file_name: $('Build Full Document').item.json.file_name,
      file_id: $('Build Full Document').item.json.file_id,
      document_id: $('Upsert Document Metadata').first().json.id,
      indexed_at: new Date().toISOString()
    }
  }
];

const embedding =
  $json.embedding?.values ||
  $json.embeddings?.[0]?.values ||
  $json.values ||
  null;

if (!embedding) {
  throw new Error('No se pudo extraer el embedding de la pregunta');
}

return [
  {
    json: {
      question: $('Telegram Trigger').first().json.message.text,
      chat_id: $('Telegram Trigger').first().json.message.chat.id,
      embedding: `[${embedding.join(',')}]`
    }
  }
];

