      file_id: file.id,
      file_name: file.name,
      mime_type: file.mimeType,
      version: file.version || null,
      source_url: file.webViewLink || null,
      created_time: file.createdTime || null,
      modified_time: file.modifiedTime || null,
      document_date: file.modifiedTime || file.createdTime || null
    }
  }
];

const meta = $('Prepare File Metadata').item.json;
const extracted = $('Extract Document Date').first().json;

const plainText = extracted.extracted_pdf_text || '';
const effectiveDate = extracted.document_date || null;

const sourceHeader = [
  `[FUENTE]`,
  `archivo: ${meta.file_name || ''}`,
  `fecha_documento: ${effectiveDate || 'desconocida'}`,
  `file_id: ${meta.file_id || ''}`,
  `mime_type: ${meta.mime_type || ''}`,
  `version: ${meta.version || ''}`,
  `url: ${meta.source_url || ''}`,
  `evidencia_fecha: ${extracted.date_evidence || ''}`,
  `[/FUENTE]`
].join('\n');

return [
  {
    json: {
      file_id: meta.file_id,
      file_name: meta.file_name,
      mime_type: meta.mime_type,
      version: meta.version,
      source_url: meta.source_url,
      document_date: effectiveDate,
      date_evidence: extracted.date_evidence || null,
      full_text: `${sourceHeader}\n\n${plainText}`
    }
  }
];

const rows = $input.all();

if (!rows.length) {
  return [
    {
      json: {
        question: $('Extract Question Embedding').first().json.question,
        chat_id: $('Extract Question Embedding').first().json.chat_id,
        has_context: false,
        context: '',
        sources: []
      }
    }
  ];
}

const sources = [];
const contextParts = [];

for (const item of rows) {
  const r = item.json;

  sources.push({
    filename: r.filename || r.file_name || 'Documento sin nombre',
    date_created: r.date_created,
    source_url: r.source_url,
    similarity: r.similarity
  });

  contextParts.push(
`Archivo: ${r.filename || r.file_name || 'Documento sin nombre'}
Fecha: ${r.date_created}
URL: ${r.source_url || 'sin URL'}
Contenido:
${r.chunk_text}`
  );
}

return [
  {
    json: {
      question: $('Extract Question Embedding').first().json.question,
      chat_id: $('Extract Question Embedding').first().json.chat_id,
      has_context: true,
      context: contextParts.join('\n\n---\n\n'),
      sources
    }
  }
];

return [
  {
    json: {
      question: $('Build Context').first().json.question,
      chat_id: $('Build Context').first().json.chat_id,
      response: 'No encuentro esa información en los documentos indexados.',
      sources: '[]',
      has_context: false
    }
  }
];

const input = $input.first().json;
const text = input.text || '';

const patterns = [
  /Date:\s*(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+\d{1,2}:\d{2}:\d{2}\s*(AM|PM))?/i,
  /Sent:\s*(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+\d{1,2}:\d{2}:\d{2}\s*(AM|PM))?/i,
  /Fecha:\s*(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+\d{1,2}:\d{2}:\d{2})?/i,
  /Enviado el:\s*(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+\d{1,2}:\d{2}:\d{2})?/i
];

let documentDate = null;
let dateEvidence = null;

for (const regex of patterns) {
  const match = text.match(regex);
  if (match) {
    const month = String(match[1]).padStart(2, '0');
    const day = String(match[2]).padStart(2, '0');
    const year = match[3];

    documentDate = `${year}-${month}-${day}`;
    dateEvidence = match[0];
    break;
  }
}

return [
  {
    json: {
      extracted_pdf_text: text,
      document_date: documentDate,
      date_evidence: dateEvidence,
      date_found: !!documentDate
    }
  }
];

const fileName =
  $json.file_name ??
  ($json.file_id ? `archivo_${$json.file_id}.pdf` : null);

const driveFileId = $json.file_id ?? null;

if (!fileName) {
  throw new Error('Falta file_name antes de insertar en documents');
}

if (!driveFileId) {
  throw new Error('Falta file_id antes de insertar en documents');
}

// date_created en tu tabla es NOT NULL.
// Si has podido extraer document_date del PDF, úsala.
// Si no, usa la fecha actual para no romper el insert.
const dateCreated =
  $json.document_date
    ? `${$json.document_date} 00:00:00`
    : new Date().toISOString().slice(0, 19).replace('T', ' ');

return [
  {
    json: {
      file_name: fileName,
      file_type: $json.mime_type ?? 'application/pdf',
      folder_path: '/',
      date_created: dateCreated,
      date_added: new Date().toISOString().slice(0, 19).replace('T', ' '),
      drive_file_id: driveFileId,
      document_date: $json.document_date ?? null,
      indexed_at: new Date().toISOString(),
      date_evidence: $json.date_evidence ?? null,
      version: $json.version ?? null,
      source_url: $json.source_url ?? null
    }
  }
];

parameters.query:
WITH deleted AS (
  DELETE FROM document_chunks
  WHERE document_id = {{ $('Upsert Document Metadata').first().json.id }}
  RETURNING document_id
)
SELECT COALESCE(
  (SELECT document_id FROM deleted LIMIT 1),
  {{ $('Upsert Document Metadata').first().json.id }}
) AS document_id;

